import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import AVATAR from "../../../assets/images/icons/male.png";
import AuthService from "../../../services/auth.service";

export const DashboardSidebar = () => {
  const [t, i18n] = useTranslation();
  const pathname = window.location.pathname;
  const [user, setUser] = useState();
  useEffect(async () => {
    setUser(AuthService.getCurrentUser());
  }, []);
  return (
    <div className="profile-sidebar">
      <div className="widget-profile pro-widget-content">
        <div className="profile-info-widget">
          <a href="#0" className="booking-doc-img">
            <img src={AVATAR} alt="User" />
          </a>
          <div className="profile-det-info">
            <h3>{AuthService.getCurrentUser().email}</h3>
            <div className="patient-details">
              <h5>
                <i className="fas fa-birthday-cake"></i> 24 Jul 1983, 38 years
              </h5>
              <h5 className="mb-0">
                <i className="fas fa-map-marker-alt"></i> Newyork, USA
              </h5>
            </div>
          </div>
        </div>
      </div>
      <div className="dashboard-widget">
        <nav className="dashboard-menu">
          <ul>
            {/* <li
              className={`${pathname === "/account-dashboard" ? "active" : ""}`}
            >
              <Link to="/account-dashboard">
                <i className="fas fa-columns"></i>
                <span>Dashboard</span>
              </Link>
            </li> */}
            <li className={pathname === "/account-profile" ? "active" : ""}>
              <Link to="/account-profile">
                <i className="fas fa-user-cog"></i>
                <span>{t("ProfileSettings")}</span>
              </Link>
            </li>
            <li
              className={pathname === "/account-appointments" ? "active" : ""}
            >
              <Link to="/account-appointments">
                <i className="fas fa-calendar-alt"></i>
                <span>{t("Appointments")}</span>
              </Link>
            </li>
            {user?.roles?.length > 0 &&
              user?.roles.filter((u) => u === "ROLE_ADMIN")?.length > 0 && (
                <>
                  <li
                    className={
                      pathname === "/account-specialities" ? "active" : ""
                    }
                  >
                    {/* <Link to="/account-specialities">
                <i className="fas fa-stethoscope"></i>
                <span>Specialities</span>
              </Link> */}

                    <Link to="/admin/specialities">
                      <i className="fas fa-stethoscope"></i>
                      <span>{t("Specialities")}</span>
                    </Link>
                  </li>
                  <li className={pathname === "/admin/Doctors" ? "active" : ""}>
                    <Link to="/admin/Doctors">
                      <i className="fas fa-users"></i>
                      <span>{t("Doctors")}</span>
                    </Link>
                  </li>
                  <li className={pathname === "/admin/Users" ? "active" : ""}>
                    <Link to="/admin/Users">
                      <i className="fas fa-users"></i>
                      <span>{t("Users")}</span>
                    </Link>
                  </li>
                  <li
                    className={pathname === "/admin/Countries" ? "active" : ""}
                  >
                    <Link to="/admin/Countries">
                      <i className="fas fa-gear"></i>
                      <span>{t("Countries")}</span>
                    </Link>
                  </li>
                  <li className={pathname === "/admin/Cities" ? "active" : ""}>
                    <Link to="/admin/Cities">
                      <i className="fas fa-gear"></i>
                      <span>{t("Cities")}</span>
                    </Link>
                  </li>
                  <li
                    className={pathname === "/admin/Facilities" ? "active" : ""}
                  >
                    <Link to="/admin/Facilities">
                      <i className="fas fa-gear"></i>
                      <span>{t("Facilities")}</span>
                    </Link>
                  </li>
                  <li
                    className={pathname === "/admin/Treatments" ? "active" : ""}
                  >
                    <Link to="/admin/Treatments">
                      <i className="fas fa-gear"></i>
                      <span>{t("Treatments")}</span>
                    </Link>
                  </li>
                </>
              )}
            <li
              className={
                pathname === "/account-change-password" ? "active" : ""
              }
            >
              <Link to="/account-change-password">
                <i className="fas fa-lock"></i>
                <span>{t("ChangePassword")}</span>
              </Link>
            </li>
          </ul>
        </nav>
      </div>
    </div>
  );
};
export default DashboardSidebar;
