import { Country, City } from "country-state-city";

const allowedCountries = ["IQ", "JO", "RU", "SA"];
const getCountriesList = () =>
  Country.getAllCountries().filter((c) => allowedCountries.includes(c.isoCode));

const getCitiesOfCountry = (countryCode) =>
  City.getCitiesOfCountry(countryCode);

const getCountryOfCode = (countryCode) => Country.getCountryByCode(countryCode);

const CountryCity = {
  getCountriesList,
  getCitiesOfCountry,
  getCountryOfCode,
};

export default CountryCity;
